import React, { useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import {
    Heart, Sparkles, Moon, Sun, Volume2, Zap, Calendar, Star, Smile, Coffee,
    Music, Flame, Cloud, Umbrella, Camera, Gift, Flower2, Feather, Palette,
    Rocket, Crown, Diamond, Cherry, Cake, IceCream, Pizza, Apple, Carrot, Cookie
} from 'lucide-react';

// ==================== 常量定义 ====================
const AVAILABLE_ICONS = {
    Heart, Sparkles, Moon, Sun, Volume2, Zap, Calendar, Star, Smile, Coffee,
    Music, Flame, Cloud, Umbrella, Camera, Gift, Flower2, Feather, Palette,
    Rocket, Crown, Diamond, Cherry, Cake, IceCream, Pizza, Apple, Carrot, Cookie
};

const THEME_COLORS = [
    { name: '樱花粉', class: 'text-pink-500', bg: 'bg-pink-500', gradient: 'from-pink-400 to-pink-600' },
    { name: '薰衣草紫', class: 'text-purple-500', bg: 'bg-purple-500', gradient: 'from-purple-400 to-purple-600' },
    { name: '天空蓝', class: 'text-blue-500', bg: 'bg-blue-500', gradient: 'from-blue-400 to-blue-600' },
    { name: '薄荷绿', class: 'text-emerald-400', bg: 'bg-emerald-400', gradient: 'from-emerald-300 to-emerald-500' },
    { name: '蜜桃橙', class: 'text-orange-400', bg: 'bg-orange-400', gradient: 'from-orange-300 to-orange-500' },
    { name: '柠檬黄', class: 'text-yellow-500', bg: 'bg-yellow-500', gradient: 'from-yellow-400 to-yellow-600' },
    { name: '玫瑰红', class: 'text-rose-500', bg: 'bg-rose-500', gradient: 'from-rose-400 to-rose-600' },
    { name: '青柠绿', class: 'text-lime-500', bg: 'bg-lime-500', gradient: 'from-lime-400 to-lime-600' },
    { name: '水蓝色', class: 'text-cyan-500', bg: 'bg-cyan-500', gradient: 'from-cyan-400 to-cyan-600' },
    { name: '紫罗兰', class: 'text-violet-500', bg: 'bg-violet-500', gradient: 'from-violet-400 to-violet-600' },
    { name: '珊瑚粉', class: 'text-pink-400', bg: 'bg-pink-400', gradient: 'from-pink-300 to-pink-500' },
    { name: '蔷薇紫', class: 'text-fuchsia-500', bg: 'bg-fuchsia-500', gradient: 'from-fuchsia-400 to-fuchsia-600' }
];

// ==================== 基础组件 ====================

// 图标按钮组件
function IconButton({ iconName, colorIndex = 0, onClick }) {
    const IconComponent = AVAILABLE_ICONS[iconName];
    const colorClass = THEME_COLORS[colorIndex].class;

    return (
        <button
            onClick={onClick}
            className="group relative hover:scale-110 transition-transform"
        >
            <IconComponent className={colorClass} size={20} />
            <div className="absolute -top-1 -right-1 w-2 h-2 bg-pink-400 rounded-full opacity-0 group-hover:opacity-100 transition-opacity" />
        </button>
    );
}

// 参数标题组件
function ParamHeader({ label, iconName = 'Star', colorIndex = 0, onIconClick }) {
    return (
        <div className="flex items-center gap-2">
            <IconButton iconName={iconName} colorIndex={colorIndex} onClick={onIconClick} />
            <span className="font-semibold text-gray-700">{label}</span>
        </div>
    );
}

// 卡片容器组件
function ParamCard({ children }) {
    return (
        <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
            {children}
        </div>
    );
}

// ==================== 图标颜色选择器 ====================

function IconColorPicker({
    paramKey,
    currentIcon,
    currentColor,
    onSelectIcon,
    onSelectColor,
    onClose,
    position,
    buttonRef
}) {
    const pickerRef = useRef(null);
    const [activeTab, setActiveTab] = useState('icon');

    useEffect(() => {
        const handleClickOutside = (event) => {
            if (pickerRef.current && !pickerRef.current.contains(event.target)) {
                if (buttonRef.current && !buttonRef.current.contains(event.target)) {
                    onClose();
                }
            }
        };

        document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [paramKey, onClose, buttonRef]);

    return createPortal(
        <div
            ref={pickerRef}
            className="fixed z-[9999] bg-white rounded-2xl shadow-2xl border-2 border-pink-200 w-80"
            style={{ top: `${position.top}px`, left: `${position.left}px` }}
        >
            {/* 标签页头部 */}
            <div className="flex border-b-2 border-pink-100">
                <button
                    onClick={() => setActiveTab('icon')}
                    className={`flex-1 py-3 font-bold text-sm transition-all ${
                        activeTab === 'icon'
                            ? 'text-pink-600 bg-gradient-to-b from-pink-50 to-white border-b-2 border-pink-500'
                            : 'text-gray-400 hover:text-gray-600'
                    }`}
                >
                    <Sparkles className="inline-block mr-1" size={14} />
                    选择图标
                </button>
                <button
                    onClick={() => setActiveTab('color')}
                    className={`flex-1 py-3 font-bold text-sm transition-all ${
                        activeTab === 'color'
                            ? 'text-pink-600 bg-gradient-to-b from-pink-50 to-white border-b-2 border-pink-500'
                            : 'text-gray-400 hover:text-gray-600'
                    }`}
                >
                    <Palette className="inline-block mr-1" size={14} />
                    选择颜色
                </button>
            </div>

            {/* 内容区域 */}
            <div className="p-4">
                {activeTab === 'icon' ? (
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-bold text-gray-700">当前图标预览</span>
                            <div className={`p-2 rounded-lg bg-gradient-to-br ${THEME_COLORS[currentColor].gradient}`}>
                                {React.createElement(AVAILABLE_ICONS[currentIcon], { className: 'text-white', size: 24 })}
                            </div>
                        </div>
                        <div className="grid grid-cols-6 gap-2 max-h-64 overflow-y-auto pr-1 scrollbar-thin scrollbar-thumb-pink-200 scrollbar-track-gray-100">
                            {Object.entries(AVAILABLE_ICONS).map(([name, Icon]) => (
                                <button
                                    key={name}
                                    onClick={() => onSelectIcon(name)}
                                    className={`p-2 rounded-lg transition-all hover:scale-110 ${
                                        currentIcon === name
                                            ? `bg-gradient-to-br ${THEME_COLORS[currentColor].gradient} text-white shadow-lg ring-2 ring-pink-300`
                                            : 'bg-gray-100 text-gray-600 hover:bg-pink-100'
                                    }`}
                                    title={name}
                                >
                                    <Icon size={20} />
                                </button>
                            ))}
                        </div>
                    </div>
                ) : (
                    <div className="space-y-3">
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-bold text-gray-700">当前颜色预览</span>
                            <div className={`p-2 rounded-lg bg-gradient-to-br ${THEME_COLORS[currentColor].gradient}`}>
                                {React.createElement(AVAILABLE_ICONS[currentIcon], { className: 'text-white', size: 24 })}
                            </div>
                        </div>
                        <div className="grid grid-cols-3 gap-3">
                            {THEME_COLORS.map((color, index) => (
                                <button
                                    key={index}
                                    onClick={() => onSelectColor(index)}
                                    className={`relative group transition-all hover:scale-105 ${
                                        currentColor === index ? 'scale-110' : ''
                                    }`}
                                >
                                    <div className={`h-16 rounded-xl bg-gradient-to-br ${color.gradient} shadow-lg transition-all ${
                                        currentColor === index ? 'ring-4 ring-pink-300 shadow-xl' : 'hover:shadow-xl'
                                    }`}>
                                        <div className="h-full flex items-center justify-center">
                                            {React.createElement(AVAILABLE_ICONS[currentIcon], { className: 'text-white', size: 28 })}
                                        </div>
                                    </div>
                                    <div className="mt-1 text-xs font-semibold text-gray-600 text-center">
                                        {color.name}
                                    </div>
                                    {currentColor === index && (
                                        <div className="absolute -top-1 -right-1">
                                            <Heart className="text-pink-500 fill-pink-500 animate-pulse" size={16} />
                                        </div>
                                    )}
                                </button>
                            ))}
                        </div>
                    </div>
                )}
            </div>

            {/* 底部关闭按钮 */}
            <div className="border-t-2 border-pink-100 p-3">
                <button
                    onClick={onClose}
                    className="w-full py-2 bg-gradient-to-r from-pink-400 to-purple-400 text-white font-bold rounded-xl hover:shadow-lg transition-all hover:scale-105"
                >
                    完成 ♡
                </button>
            </div>
        </div>,
        document.body
    );
}

// ==================== 参数组件 ====================

// 约会计数器
function DateCounter({
    value = 0,
    onChange,
    iconName = 'Calendar',
    colorIndex = 0,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between">
                <ParamHeader
                    label="约会次数"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <div className="flex items-center gap-3">
                    <div className="flex items-center gap-1">
                        {[...Array(Math.min(value, 5))].map((_, i) => (
                            <Heart
                                key={i}
                                className="text-rose-400 fill-rose-400 animate-pulse"
                                size={16}
                                style={{ animationDelay: `${i * 0.1}s` }}
                            />
                        ))}
                    </div>
                    <span className="text-2xl font-bold text-rose-500 min-w-12 text-center">
                        {value}
                    </span>
                    <button
                        onClick={() => onChange(value + 1)}
                        className="group relative px-4 py-2 bg-gradient-to-r from-rose-400 to-pink-500 text-white font-bold rounded-xl hover:scale-110 active:scale-95 transition-all shadow-lg hover:shadow-xl"
                    >
                        <span className="relative z-10">+1</span>
                        <div className="absolute inset-0 bg-gradient-to-r from-rose-500 to-pink-600 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity" />
                    </button>
                </div>
            </div>
        </ParamCard>
    );
}

// 心情选择器
function MoodSelector({
    value = null,
    onChange,
    iconName = 'Star',
    colorIndex = 5,
    onIconClick
}) {
    const [pendingMood, setPendingMood] = useState(null);

    const moods = [
        { value: 1, emoji: '😊', label: '开心' },
        { value: 2, emoji: '😍', label: '爱恋' },
        { value: 3, emoji: '🥰', label: '甜蜜' },
        { value: 4, emoji: '✨', label: '兴奋' },
        { value: 5, emoji: '💖', label: '幸福' }
    ];

    const handleMoodClick = (moodValue) => {
        if (pendingMood === moodValue) {
            onChange(moodValue);
            setPendingMood(null);
        } else {
            setPendingMood(moodValue);
            if (value !== moodValue) {
                onChange(null);
            }
        }
    };

    return (
        <ParamCard>
            <div className="flex items-center justify-between mb-3">
                <ParamHeader
                    label="心情状态"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                {pendingMood && (
                    <span className="text-xs text-pink-500 font-semibold animate-pulse">
                        再点一次确认 ♡
                    </span>
                )}
            </div>
            <div className="flex gap-2">
                {moods.map((mood) => {
                    const isPending = pendingMood === mood.value;
                    const isSelected = value === mood.value;

                    return (
                        <button
                            key={mood.value}
                            onClick={() => handleMoodClick(mood.value)}
                            className={`relative flex-1 py-3 rounded-xl font-bold transition-all ${
                                isSelected
                                    ? 'bg-gradient-to-r from-pink-500 to-rose-500 text-white shadow-xl scale-110 ring-4 ring-pink-300'
                                    : isPending
                                        ? 'bg-gradient-to-r from-pink-300 to-rose-300 text-white shadow-lg scale-105 ring-2 ring-pink-400 animate-pulse'
                                        : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
                            }`}
                        >
                            <div className="flex flex-col items-center gap-1">
                                <span className="text-lg">{mood.emoji}</span>
                                <span className="text-xs">{mood.label}</span>
                            </div>
                            {isPending && (
                                <div className="absolute -top-1 -right-1 w-3 h-3 bg-pink-500 rounded-full animate-ping" />
                            )}
                            {isSelected && (
                                <div className="absolute -top-1 -right-1">
                                    <Heart className="text-white fill-white" size={12} />
                                </div>
                            )}
                        </button>
                    );
                })}
            </div>
        </ParamCard>
    );
}

// 滑块控制器
function SliderControl({
    label,
    value = 50,
    min = 0,
    max = 100,
    onChange,
    iconName = 'Star',
    colorIndex = 0,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between mb-2">
                <ParamHeader
                    label={label}
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <span className={`text-sm font-bold ${THEME_COLORS[colorIndex].class}`}>
                    {value}%
                </span>
            </div>
            <input
                type="range"
                min={min}
                max={max}
                value={value}
                onChange={(e) => onChange(parseInt(e.target.value))}
                className={`w-full h-2 bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-5 [&::-webkit-slider-thumb]:h-5 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-white [&::-webkit-slider-thumb]:shadow-lg [&::-webkit-slider-thumb]:border-2 [&::-webkit-slider-thumb]:border-pink-400`}
            />
        </ParamCard>
    );
}

// 速度选择器
function SpeedSelector({
    value = 3,
    min = 1,
    max = 5,
    onChange,
    iconName = 'Zap',
    colorIndex = 2,
    onIconClick
}) {
    const options = Array.from({ length: max - min + 1 }, (_, i) => min + i);

    return (
        <ParamCard>
            <div className="flex items-center justify-between mb-3">
                <ParamHeader
                    label="速度"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
            </div>
            <div className="flex gap-2">
                {options.map((speed) => (
                    <button
                        key={speed}
                        onClick={() => onChange(speed)}
                        className={`flex-1 py-2 rounded-xl font-bold transition-all ${
                            value === speed
                                ? `bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} text-white shadow-lg scale-110`
                                : 'bg-white/80 text-gray-600 hover:bg-white hover:scale-105'
                        }`}
                    >
                        {speed}
                    </button>
                ))}
            </div>
        </ParamCard>
    );
}

// 爱心计数器
function HeartsCounter({
    value = 5,
    min = 0,
    max = 10,
    onChange,
    iconName = 'Heart',
    colorIndex = 6,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between">
                <ParamHeader
                    label="爱心数量"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <div className="flex items-center gap-2">
                    <button
                        onClick={() => onChange(Math.max(min, value - 1))}
                        className={`w-8 h-8 rounded-full bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} text-white font-bold hover:scale-110 transition-transform shadow-md`}
                    >
                        −
                    </button>
                    <span className={`text-lg font-bold ${THEME_COLORS[colorIndex].class} w-8 text-center`}>
                        {value}
                    </span>
                    <button
                        onClick={() => onChange(Math.min(max, value + 1))}
                        className={`w-8 h-8 rounded-full bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} text-white font-bold hover:scale-110 transition-transform shadow-md`}
                    >
                        +
                    </button>
                </div>
            </div>
        </ParamCard>
    );
}

// 开关切换器
function ToggleSwitch({
    label,
    value = false,
    onChange,
    iconName = 'Sparkles',
    colorIndex = 5,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between">
                <ParamHeader
                    label={label}
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <button
                    onClick={() => onChange(!value)}
                    className={`w-14 h-7 rounded-full transition-all shadow-inner ${
                        value ? `bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient}` : 'bg-gray-300'
                    }`}
                >
                    <div
                        className={`w-6 h-6 bg-white rounded-full shadow-lg transition-transform ${
                            value ? 'translate-x-7' : 'translate-x-0.5'
                        }`}
                    />
                </button>
            </div>
        </ParamCard>
    );
}

// 主题选择器
function ThemeSelector({
    value = 'pink',
    onChange,
    iconName = 'Moon',
    colorIndex = 9,
    onIconClick
}) {
    const themes = [
        { value: 'pink', gradient: 'from-pink-300 to-purple-300', ring: 'ring-pink-400' },
        { value: 'blue', gradient: 'from-blue-300 to-cyan-300', ring: 'ring-blue-400' },
        { value: 'peach', gradient: 'from-orange-300 to-pink-300', ring: 'ring-orange-400' }
    ];

    return (
        <ParamCard>
            <div className="flex items-center gap-2 mb-3">
                <ParamHeader
                    label="主题色彩"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
            </div>
            <div className="flex gap-2">
                {themes.map((theme) => (
                    <button
                        key={theme.value}
                        onClick={() => onChange(theme.value)}
                        className={`flex-1 h-10 rounded-xl bg-gradient-to-r ${theme.gradient} transition-all ${
                            value === theme.value ? `ring-4 ${theme.ring} scale-105 shadow-lg` : 'hover:scale-105'
                        }`}
                    />
                ))}
            </div>
        </ParamCard>
    );
}

// 数字输入器
function NumberInput({
    label,
    value = 50,
    min = 0,
    max = 100,
    onChange,
    iconName = 'Zap',
    colorIndex = 7,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between">
                <ParamHeader
                    label={label}
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <input
                    type="number"
                    min={min}
                    max={max}
                    value={value}
                    onChange={(e) => onChange(Math.min(max, Math.max(min, parseInt(e.target.value) || 0)))}
                    className={`w-20 px-3 py-2 bg-white rounded-xl border-2 ${THEME_COLORS[colorIndex].bg} border-opacity-30 text-center font-bold ${THEME_COLORS[colorIndex].class} focus:outline-none focus:ring-2 focus:ring-pink-400 focus:border-transparent`}
                />
            </div>
        </ParamCard>
    );
}

// ==================== 主容器组件 ====================

function CuteContainer({ theme = 'pink', children, title = '可爱参数面板', subtitle = '调整你的专属设置 ♡' }) {
    const themes = {
        pink: 'from-pink-100 to-purple-100',
        blue: 'from-blue-100 to-cyan-100',
        peach: 'from-orange-100 to-pink-100'
    };

    return (
        <div className="min-h-screen flex items-center justify-center p-4 bg-gradient-to-br from-pink-50 via-purple-50 to-blue-50">
            <div className={`w-full max-w-md bg-gradient-to-br ${themes[theme]} rounded-3xl shadow-2xl p-6 space-y-4 border-4 border-white/50`}>
                <div className="text-center mb-6">
                    <div className="flex items-center justify-center gap-2 mb-2">
                        <Sparkles className="text-pink-500" size={24} />
                        <h2 className="text-2xl font-bold bg-gradient-to-r from-pink-500 to-purple-500 bg-clip-text text-transparent">
                            {title}
                        </h2>
                        <Sparkles className="text-purple-500" size={24} />
                    </div>
                    <p className="text-sm text-gray-600">{subtitle}</p>
                    <p className="text-xs text-pink-400 mt-1">点击图标可更换图标和颜色哦 ~</p>
                </div>

                {children}

                <div className="text-center pt-4">
                    <p className="text-xs text-gray-500">♡ 愿你每天都充满快乐 ♡</p>
                </div>
            </div>
        </div>
    );
}

// ==================== 主应用组件（示例） ====================

function CuteParameterCard() {
    const [params, setParams] = useState({
        brightness: 75,
        volume: 60,
        speed: 3,
        hearts: 5,
        sparkle: true,
        theme: 'pink',
        energy: 80,
        dateCount: 0,
        mood: null
    });

    const [paramIcons, setParamIcons] = useState({
        brightness: 'Sun',
        volume: 'Volume2',
        speed: 'Zap',
        hearts: 'Heart',
        sparkle: 'Sparkles',
        theme: 'Moon',
        energy: 'Zap',
        dateCount: 'Calendar',
        mood: 'Star'
    });

    const [paramColors, setParamColors] = useState({
        brightness: 3,
        volume: 1,
        speed: 2,
        hearts: 6,
        sparkle: 5,
        theme: 9,
        energy: 7,
        dateCount: 0,
        mood: 5
    });

    const [iconPickerOpen, setIconPickerOpen] = useState(null);
    const [pickerPosition, setPickerPosition] = useState({ top: 0, left: 0 });
    const buttonRefs = useRef({});

    const handleIconClick = (paramKey) => {
        if (iconPickerOpen === paramKey) {
            setIconPickerOpen(null);
            return;
        }

        const button = buttonRefs.current[paramKey];
        if (button) {
            const rect = button.getBoundingClientRect();
            const viewportWidth = window.innerWidth;
            const pickerWidth = 320;

            let left = rect.left + window.scrollX;
            if (left + pickerWidth > viewportWidth) {
                left = viewportWidth - pickerWidth - 16;
            }

            setPickerPosition({
                top: rect.bottom + window.scrollY + 8,
                left: left
            });
            setIconPickerOpen(paramKey);
        }
    };

    const createIconClickHandler = (paramKey) => {
        return (event) => {
            // 确保引用指向实际的 DOM 元素
            if (!buttonRefs.current[paramKey]) {
                buttonRefs.current[paramKey] = event.currentTarget;
            }
            handleIconClick(paramKey);
        };
    };

    return (
        <CuteContainer theme={params.theme}>
            <DateCounter
                value={params.dateCount}
                onChange={(val) => setParams(prev => ({ ...prev, dateCount: val }))}
                iconName={paramIcons.dateCount}
                colorIndex={paramColors.dateCount}
                onIconClick={createIconClickHandler('dateCount')}
            />

            <MoodSelector
                value={params.mood}
                onChange={(val) => setParams(prev => ({ ...prev, mood: val }))}
                iconName={paramIcons.mood}
                colorIndex={paramColors.mood}
                onIconClick={createIconClickHandler('mood')}
            />

            <SliderControl
                label="亮度"
                value={params.brightness}
                onChange={(val) => setParams(prev => ({ ...prev, brightness: val }))}
                iconName={paramIcons.brightness}
                colorIndex={paramColors.brightness}
                onIconClick={createIconClickHandler('brightness')}
            />

            <SliderControl
                label="音量"
                value={params.volume}
                onChange={(val) => setParams(prev => ({ ...prev, volume: val }))}
                iconName={paramIcons.volume}
                colorIndex={paramColors.volume}
                onIconClick={createIconClickHandler('volume')}
            />

            <SpeedSelector
                value={params.speed}
                onChange={(val) => setParams(prev => ({ ...prev, speed: val }))}
                iconName={paramIcons.speed}
                colorIndex={paramColors.speed}
                onIconClick={createIconClickHandler('speed')}
            />

            <HeartsCounter
                value={params.hearts}
                onChange={(val) => setParams(prev => ({ ...prev, hearts: val }))}
                iconName={paramIcons.hearts}
                colorIndex={paramColors.hearts}
                onIconClick={createIconClickHandler('hearts')}
            />

            <ToggleSwitch
                label="闪闪特效"
                value={params.sparkle}
                onChange={(val) => setParams(prev => ({ ...prev, sparkle: val }))}
                iconName={paramIcons.sparkle}
                colorIndex={paramColors.sparkle}
                onIconClick={createIconClickHandler('sparkle')}
            />

            <ThemeSelector
                value={params.theme}
                onChange={(val) => setParams(prev => ({ ...prev, theme: val }))}
                iconName={paramIcons.theme}
                colorIndex={paramColors.theme}
                onIconClick={createIconClickHandler('theme')}
            />

            <NumberInput
                label="能量值"
                value={params.energy}
                onChange={(val) => setParams(prev => ({ ...prev, energy: val }))}
                iconName={paramIcons.energy}
                colorIndex={paramColors.energy}
                onIconClick={createIconClickHandler('energy')}
            />

            {iconPickerOpen && (
                <IconColorPicker
                    paramKey={iconPickerOpen}
                    currentIcon={paramIcons[iconPickerOpen]}
                    currentColor={paramColors[iconPickerOpen]}
                    onSelectIcon={(icon) => setParamIcons(prev => ({ ...prev, [iconPickerOpen]: icon }))}
                    onSelectColor={(color) => setParamColors(prev => ({ ...prev, [iconPickerOpen]: color }))}
                    onClose={() => setIconPickerOpen(null)}
                    position={pickerPosition}
                    buttonRef={buttonRefs.current[iconPickerOpen]}
                />
            )}
        </CuteContainer>
    );
}

export default CuteParameterCard;
